insert into events (title, venue, neighborhood_id, starts_at, price, description, link, status) values ('National Gallery of Modern Art (NGMA)', 'Manikyavelu Mansion, 49 Palace Road', null, now() + interval '3 days', 20, 'Tue–Sun, 10 AM–5 PM — Modern Indian art (Ravi Varma, Sher-Gil, Tagore) for INR 20; free for students up to class XII.', 'https://ngmaindia.gov.in/ngma_bangaluru.asp', 'approved');
